async (page) => {
  // Helper: convert grid coords to viewport coords
  const gridToScreen = async (gridX, gridY) => {
    return await page.evaluate(({gx, gy}) => {
      const renderer = window.game.renderer;
      const camera = window.game.camera;
      const tileSize = renderer.tileSize || 16;
      const scale = renderer.drawingScale || renderer.scale || 2;
      const canvas = document.getElementById('text-canvas');
      const rect = canvas.getBoundingClientRect();
      return {
        x: Math.round((gx * tileSize - camera.x) * scale + rect.left),
        y: Math.round((gy * tileSize - camera.y) * scale + rect.top)
      };
    }, {gx: gridX, gy: gridY});
  };

  const click = async (x, y) => {
    await page.evaluate(({x, y}) => {
      document.getElementById('text-canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, {x, y});
  };

  // Click Rat at grid (176, 154) -> viewport (379, 224)
  const pos = await gridToScreen(176, 154);
  console.log('Rat screen pos:', JSON.stringify(pos));

  await click(pos.x, pos.y);
  await page.waitForTimeout(4000);

  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return gs ? { 
      pos: gs.player_position, 
      last_combat: gs.last_combat,
      last_xp: gs.last_xp_event,
      nearest_mob: gs.nearest_mob ? { name: gs.nearest_mob.name, dist: gs.nearest_mob.distance, hp: gs.nearest_mob.hp } : null
    } : null;
  });
  return JSON.stringify(state);
}

