async (page) => {
  const result = await page.evaluate(() => {
    const game = window.game;
    const player = game.player;
    const input = game.input;
    const entities = game.entities.entities;

    // Find nearest Oak tree
    let closestTree = null, closestDist = Infinity;
    for (const [id, e] of Object.entries(entities)) {
      if (!e || e.type !== 10) continue;
      const dist = Math.hypot(e.gridX - player.gridX, e.gridY - player.gridY);
      if (dist < closestDist) { closestDist = dist; closestTree = e; }
    }

    if (!closestTree) return 'No trees found';

    // Try setObjectTarget
    player.setObjectTarget(closestTree);

    return `Targeting Oak at (${closestTree.gridX}, ${closestTree.gridY}), dist=${closestDist.toFixed(1)}, target=${JSON.stringify(player.target ? {type: player.target.type, x: player.target.gridX, y: player.target.gridY} : null)}`;
  });
  return result;
}

async (page) => {
  // Find the resource/target interaction packet opcode by examining the game's socket module
  const result = await page.evaluate(() => {
    const game = window.game;

    // Look for relevant opcodes/packets in socket
    const info = {};

    // Check what methods exist on the socket/network
    if (game.socket) {
      info.socketMethods = Object.getOwnPropertyNames(game.socket.constructor.prototype).filter(m => 
        !['constructor'].includes(m)
      );
    }

    // Check what the target/resource packet looks like in the sender
    if (game.socket?.messages) {
      info.messagesMethods = Object.getOwnPropertyNames(game.socket.messages.constructor.prototype);
    }

    // Try to find the Opcodes object
    const keys = Object.keys(window).filter(k => 
      typeof window[k] === 'object' && window[k] !== null && 
      Object.keys(window[k] || {}).some(subk => /opcode|packet|Packet/i.test(subk))
    );
    info.globalKeys = keys.slice(0, 10);

    // Search for target-related send functions
    const playerProto = Object.getOwnPropertyNames(game.player.constructor.prototype);
    info.playerMethods = playerProto.filter(m => /target|resource|gather|attack|object/i.test(m));

    return JSON.stringify(info);
  });
  return result;
}
